  <style>
    .dataTables_filter input {
      width: 250px;
      /* Wider search box */
      height: 35px;
      /* Taller search box */
      padding: 0 10px;
      border: 1px solid #ddd;
      border-radius: 4px;
    }

    /* Customize the show entries dropdown */
    .dataTables_length select {
      width: 80px;
      /* Wider dropdown */
      height: 35px;
      /* Taller dropdown */
      padding: 5px;
      border: 1px solid #ddd;
      border-radius: 4px;
    }

    /* Add some spacing between the controls and the table */
    .dataTables_wrapper .dataTables_length,
    .dataTables_wrapper .dataTables_filter {
      margin-bottom: 15px;
    }

    /* Make the text for the controls slightly larger */
    .dataTables_wrapper .dataTables_length label,
    .dataTables_wrapper .dataTables_filter label {
      font-size: 15px;
    }
  </style>
